						err.chunk = entryChunk;
						this.errors.push(err);
						entry.setRuntimeChunk(entryChunk);
						continue outer;
					}

					entry.addDependOn(dependency);

					if (dependency.addChild(entry)) {
						entry.addParent(dependency);
					}
				}
